const PB_URL=($('Config').first().json.pbUrl||'').replace(/\/+$/,'');
const token=$('PB Auth').first().json.token; const pbH={Authorization:token};
const GET=(coll,qs)=>this.helpers.httpRequest({method:'GET',url:PB_URL+'/api/collections/'+coll+'/records',qs,headers:pbH,json:true});
const PATCH=(coll,id,b)=>this.helpers.httpRequest({method:'PATCH',url:PB_URL+'/api/collections/'+coll+'/records/'+id,headers:pbH,body:b,json:true});
// 1) control flag (Pause)
const sres=await GET('settings',{filter:"key='scrape_drain'",perPage:1});
const cfg=((sres.items&&sres.items[0])||{}).value||{};
if(cfg.enabled!==true) return [{json:{paused:true}}];
const cap=Number(cfg.batch_size||15); const staleMs=Number(cfg.stale_minutes||10)*60000;
const now=Date.now();
// 2) reconcile processing -> done (club has scrape_note) / stale -> error
const proc=await GET('scrape_queue',{filter:"status='processing'",expand:'club',perPage:200});
let inflight=0, done=0, errored=0;
for(const row of (proc.items||[])){
  const club=row.expand&&row.expand.club;
  const ls=(club&&club.last_scraped)?Date.parse(club.last_scraped):0;
  const ps=row.processed_at?Date.parse(row.processed_at):0;
  // done = the club was (re)scraped AFTER we dispatched it (works for force re-runs too,
  // where a stale scrape_note/last_scraped already existed before dispatch).
  if(ls && ps && ls>=ps){ try{await PATCH('scrape_queue',row.id,{status:'done'});}catch(_){}; done++; continue; }
  if(ps && (now-ps)>staleMs){ try{await PATCH('scrape_queue',row.id,{status:'error'});}catch(_){}; errored++; continue; }
  inflight++;
}
// 3) backpressure: only top up to the cap
const slots=Math.max(0,cap-inflight);
let fired=0;
if(slots>0){
  const q=await GET('scrape_queue',{filter:"status='queued'",sort:'enqueued_at',perPage:slots,expand:'club'});
  const nowIso=new Date().toISOString();
  for(const row of (q.items||[])){
    const clubId=(row.expand&&row.expand.club&&row.expand.club.id)||row.club;
    try{ await PATCH('scrape_queue',row.id,{status:'processing',processed_at:nowIso,attempts:(row.attempts||0)+1}); }catch(e){ continue; }
    try{ await this.helpers.httpRequest({method:'POST',url:'https://n8n-2.biceps.digital/webhook/site-scrape-club-v2',headers:{'Content-Type':'application/json'},body:{id:clubId,force:!!row.force},json:true,timeout:15000}); }catch(e){}
    fired++;
  }
}
return [{json:{inflight,slots,fired,reconciled_done:done,errored}}];
